<?php require_once 'config.php'; if (!isset($_SESSION['user_id']) || $_SESSION['role'] !== 'admin') { header("Location: login.php"); exit; } $project_id = $_GET['project_id'] ?? null; if (!$project_id) { header("Location: admin_dashboard.php"); exit; } $query = "SELECT * FROM projects WHERE id = ?"; $stmt = $conn->prepare($query); $stmt->bind_param("i", $project_id); $stmt->execute(); $project = $stmt->get_result()->fetch_assoc(); $query = "SELECT id, username FROM users WHERE role = 'staff'"; $staff_result = $conn->query($query); $staff = $staff_result->fetch_all(MYSQLI_ASSOC); $error = ''; $success = ''; if ($_SERVER['REQUEST_METHOD'] === 'POST') { $staff_id = $_POST['staff_id']; $query = "INSERT INTO project_assignments (project_id, user_id) VALUES (?, ?)"; $stmt = $conn->prepare($query); $stmt->bind_param("ii", $project_id, $staff_id); if ($stmt->execute()) { $success = 'Staff assigned successfully!'; } else { $error = 'Error assigning staff: ' . $conn->error; } } $query = "SELECT u.id, u.username FROM users u INNER JOIN project_assignments pa ON u.id = pa.user_id WHERE pa.project_id = ?"; $stmt = $conn->prepare($query); $stmt->bind_param("i", $project_id); $stmt->execute(); $assigned = $stmt->get_result()->fetch_all(MYSQLI_ASSOC); ?> <!DOCTYPE html> <html lang="en"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title>Assign Staff</title> <link rel="stylesheet" href="style.css"> </head> <body> <div class="navbar"> <h1>Assign Staff to <?php echo $project['name']; ?></h1> <a href="admin_dashboard.php" class="btn">Back to Dashboard</a> </div> <div class="container"> <?php if ($error): ?> <div class="alert alert-error"><?php echo $error; ?></div> <?php endif; ?> <?php if ($success): ?> <div class="alert alert-success"><?php echo $success; ?></div> <?php endif; ?> <form method="POST" action=""> <label for="staff_id">Select Staff Member:</label> <select id="staff_id" name="staff_id" required> <option value="">-- Select Staff --</option> <?php foreach ($staff as $member): ?> <option value="<?php echo $member['id']; ?>"><?php echo $member['username']; ?></option> <?php endforeach; ?> </select> <button type="submit" class="btn btn-success">Assign Staff</button> </form> <h3>Currently Assigned Staff:</h3> <?php if (empty($assigned)): ?> <p>No staff assigned yet.</p> <?php else: ?> <ul> <?php foreach ($assigned as $member): ?> <li><?php echo $member['username']; ?></li> <?php endforeach; ?> </ul> <?php endif; ?> </div> </body> </html>